        metrics["labelTop5"] += int(targetLabel in ranked)
        topMembers = model.contrastSemanticUnitMembers.get(ranked[0], tuple()) if ranked else tuple()
        metrics["surfaceInTop1Unit"] += int(surface in topMembers)
